// Input: Client data from manual trigger or form
return {
  json: {
    firmName: $input.first().json.firmName || 'Test Law Firm',
    address: $input.first().json.address || '123 Main St, Houston, TX',
    email: $input.first().json.email || 'test@example.com',
    practiceArea: $input.first().json.practiceArea || 'immigration',
    clientId: 'client_' + Date.now()
  }
};

// Extract run ID and poll for completion
const runId = $input.first().json.data.id;
const runUrl = `https://api.apify.com/v2/acts/compass~google-maps-scraper/runs/${runId}`;

return {
  json: {
    runId: runId,
    runUrl: runUrl,
    datasetId: $input.first().json.data.defaultDatasetId,
    clientId: $('Prepare Input').first().json.clientId
  }
};

// Check if completed
const status = $input.first().json.data.status;
const isComplete = status === 'SUCCEEDED';

if (isComplete) {
  return { json: { complete: true, data: $input.first().json.data } };
} else {
  return { json: { complete: false, status: status } };
}

// Calculate GEO Score
const placeData = $input.first().json[0];

function calculateScore(data) {
  let score = 0;

  // Coordinate precision (25)
  if (data.location?.lat && data.location?.lng) score += 20;

  // Parking info (25)
  const desc = (data.description || '').toLowerCase();
  if (desc.includes('parking')) score += 20;
  else score += 5;

  // Schema readiness (30)
  if (data.title) score += 5;
  if (data.address) score += 5;
  if (data.phone) score += 5;
  if (data.website) score += 5;
  if (data.reviews?.length > 0) score += 10;

  // Local context (20)
  if (desc.includes('houston') || desc.includes('court')) score += 15;
  else score += 5;

  return score;
}

const geoScore = calculateScore(placeData);

return {
  json: {
    clientId: $('Prepare Input').first().json.clientId,
    firmName: placeData.title,
    geoScore: geoScore,
    placeData: placeData,
    timestamp: new Date().toISOString()
  }
};

// Generate notification
const score = $input.first().json.geoScore;
const firm = $input.first().json.firmName;

let message = '';
if (score >= 80) {
  message = `✅ ${firm}: Strong GEO score (${score}/100). Minor optimizations recommended.`;
} else if (score >= 60) {
  message = `⚠️ ${firm}: Average GEO score (${score}/100). Significant improvements possible.`;
} else {
  message = `🔴 ${firm}: Poor GEO score (${score}/100). Major optimization needed.`;
}

return {
  json: {
    message: message,
    score: score,
    clientId: $input.first().json.clientId
  }
};
